examples.call:
main.sh "src/**/modifiers/added.ts" replace-block "return <T extends TraitOrRelation[]>(" "{
    const traits: Trait[] = [];
    for (const input of inputs) {
        if (isAspect(input)) {
            for (const t of input.traits) {
                traits.push(t);
            }
        } else if (isRelation(input)) {
            traits.push(input[$internal].trait);
        } else {
            traits.push(input as Trait);
        }
    }
    return createModifier(`added-${id}`, id, traits);
}"
